// Lightweight IPFS helper stubs so the app works even
// without a configured IPFS backend. All data is stored
// directly on-chain (encrypted) and these functions
// simply signal "no IPFS support" to the rest of the app.

export function hasIPFSSupport() {
  // Return false so callers know not to treat stored
  // values as CIDs or attempt gateway fetches.
  return false;
}

export async function uploadTextToIPFS(text) {
  // In a real setup, you would upload `text` to IPFS
  // and return the CID. Returning null tells callers
  // to fall back to on-chain storage only.
  return null;
}

export async function fetchTextFromIPFS(cid) {
  // Should never be called when hasIPFSSupport() is false,
  // but we return an empty string for safety.
  return "";
}
